inline_comments.message:
Regarding varargs, you can explicitly pass an array:

import java.util.*;

public class VarargsTest
{
  static public void main(String args[])
  {
    List<String> list = new LinkedList<>();
    list.add("c");
    list.add("d");

    varargs("a", "b");			// standard call
    varargs(args);				// passing an array
    varargs(list.toArray(new String[0]));	// converting a list
  }

  static public void varargs(String... args)
  {
    System.out.println("varargs called: " + Arrays.asList(args));
  }
}

$ java VarargsTest x y z
varargs called: [a, b]
varargs called: [x, y, z]
varargs called: [c, d]
